class Solution {
public:
    vector<int> topologicalSort(vector<vector<int>>& edges) {
        vector<int> order;
        vector<bool> visited(edges.size(), false);
        for (int i = 0; i < edges.size(); ++i) {
            if (!visited[i]) {
                selfDfs(i, edges, order, visited);
            }
        }
        return order;
    }

    void selfDfs(int node, vector<vector<int>>& edges, vector<int>& order, vector<bool>& visited) {
        visited[node] = true;
        for (int i = 0; i < edges[node].size(); ++i) {
            int neighbor = edges[node][i];
            if (!visited[neighbor]) {
                selfDfs(neighbor, edges, order, visited);
            }
        }
        order.push_back(node);
    }
}
